#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

os.makedirs("components", exist_ok=True)
with open("components/NavBar.js", "wb") as f: f.write(base64.b64decode(""))
print("OK components/NavBar.js")

os.makedirs("screens", exist_ok=True)
with open("screens/BatProfileScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/BatProfileScreen.js")

print()
print("Also install if not already done:")
print("  npx expo install expo-image-picker expo-image-manipulator")
print()
print("Run: npx expo start --clear --lan")
print()
print("Fixed:")
print("  - Back arrow now points left (<)")
print("  - Bat photo import restored (camera + gallery)")
print("  - Photo enhancement on import")
print("  - Heatmap and zone editor will work again")
